// Parsear datos que envia ManyChat via External Request
const body = $input.first().json.body || $input.first().json;

// ManyChat envia estos campos (configurados en el External Request):
const mensaje = body.last_input_text || body.message || '';
const nombre = body.first_name || '';
const apellido = body.last_name || '';
const subscriberId = body.subscriber_id || body.id || '';
const canal = body.channel || 'instagram';

// Custom fields de ManyChat
const customFields = body.custom_fields || {};
const ultimoAgente = customFields.ultimo_agente || '';
const ultimaInteraccion = customFields.ultima_interaccion || '';
const historialResumen = customFields.historial_resumen || '';
const temaConsulta = customFields.tema_consulta || '';
const veleroInteres = customFields.velero_interes || '';

// Seleccionar agente humanizado
const agentes = ['Laura', 'Alberto', 'Marina'];
const agentName = ultimoAgente || agentes[Math.floor(Math.random() * agentes.length)];

return [{
  json: {
    mensaje,
    nombre,
    apellido,
    subscriberId,
    canal,
    ultimoAgente,
    ultimaInteraccion,
    historialResumen,
    temaConsulta,
    veleroInteres,
    agentName
  }
}];

const agentOutput = $input.first().json;
const respuesta = agentOutput.output || 'Perdon, tuve un problema tecnico. Escribinos por WhatsApp: wa.me/5491149915143';

const fieldsData = $('Parsear Datos ManyChat').first().json;

// Detectar tema de la consulta para guardar en custom fields de ManyChat
const msg = fieldsData.mensaje.toLowerCase();
let tema = fieldsData.temaConsulta || '';
let velero = fieldsData.veleroInteres || '';

if (msg.match(/traves|naveg|salida|colonia|delta|carmelo|destino/)) tema = 'travesia';
else if (msg.match(/curso|timonel|patron|escuela|aprender|clase/)) tema = 'curso';
else if (msg.match(/velero|barco|comprar|vender|masti|brama|marejada|brisa/)) tema = 'velero';
else if (msg.match(/servicio|tecnico|reparar|mantenimiento|motor/)) tema = 'servicio';

if (msg.match(/masti/)) velero = 'masti';
else if (msg.match(/brama/)) velero = 'brama';
else if (msg.match(/marejada/)) velero = 'marejada';
else if (msg.match(/brisa/)) velero = 'brisa';

return [{
  json: {
    version: "v2",
    content: {
      messages: [
        {
          type: "text",
          text: respuesta
        }
      ],
      actions: [
        {
          action: "set_field_value",
          field_name: "ultimo_agente",
          value: fieldsData.agentName
        },
        {
          action: "set_field_value",
          field_name: "ultima_interaccion",
          value: new Date().toISOString()
        },
        {
          action: "set_field_value",
          field_name: "tema_consulta",
          value: tema
        },
        {
          action: "set_field_value",
          field_name: "velero_interes",
          value: velero
        }
      ]
    }
  }
}];
